                if (printLogEntrySchema.ThumbnailPathOption.Value != null)
                    writer.WriteString("thumbnail_path", printLogEntrySchema.ThumbnailPath);
                else
                    writer.WriteNull("thumbnail_path");

            if (printLogEntrySchema.CreatedByIdOption.IsSet)
                if (printLogEntrySchema.CreatedByIdOption.Value != null)
                    writer.WriteNumber("created_by_id", printLogEntrySchema.CreatedByIdOption.Value!.Value);
                else
                    writer.WriteNull("created_by_id");

            if (printLogEntrySchema.CreatedByUsernameOption.IsSet)
                if (printLogEntrySchema.CreatedByUsernameOption.Value != null)
                    writer.WriteString("created_by_username", printLogEntrySchema.CreatedByUsername);
                else
                    writer.WriteNull("created_by_username");
        }
    }
}
